class Graph:
    def __init__(self, num_vertices):
        self._num_vertices = num_vertices
        self._adj_matrix = [[0] * num_vertices for _ in range(num_vertices)]

    def add_edge(self, u, v):
        if 0 <= u < self._num_vertices and 0 <= v < self._num_vertices:
            self._adj_matrix[u][v] = 1
            self._adj_matrix[v][u] = 1

    def remove_edge(self, u, v):
        if 0 <= u < self._num_vertices and 0 <= v < self._num_vertices:
            self._adj_matrix[u][v] = 0
            self._adj_matrix[v][u] = 0

    def has_edge(self, u, v):
        if 0 <= u < self._num_vertices and 0 <= v < self._num_vertices:
            return self._adj_matrix[u][v] == 1
        return False

    def print_matrix(self):
        for row in self._adj_matrix:
            print(" ".join(map(str, row)))
